c
SEC("kprobe/do_sys_openat2")
int bad_loop(void *ctx) {
int i = 0;
int sum = 0;
// REJECTED: Verifier can't prove termination
while (i < 1000) {
sum += i;
i++;
}
return sum;
}

c
SEC("kprobe/do_sys_openat2")
int bad_access(void *ctx) {
int array[10];  // Size: 10 elements
// idx could be 0-255!
int idx = bpf_get_current_pid_tgid() & 0xFF;
// REJECTED: No bounds check
// Verifier tracks: idx ∈ [0, 255]
// Array bounds: [0, 9]
return array[idx];  // Potential OOB!
}

c
SEC("kprobe/do_sys_openat2")
int bad_uninit(void *ctx) {
int value;  // NOT initialized!
u32 pid = bpf_get_current_pid_tgid() >> 32;
if (pid > 1000) {
value = 42;  // Only set on THIS path
}
// What if pid <= 1000?
// value is UNINITIALIZED here!
return value;  // REJECTED
}

c
// Use bounded loop with constant limit
// Compiler unrolls, verifier accepts
for (int i = 0; i < 10; i++) {
sum += i;
}

c
// Add explicit bounds check
if (idx >= 0 && idx < 10) {
return array[idx];  // Safe!
}
return 0;

